
"use client";

import { useState, useEffect } from "react";
import Image from 'next/image';
import { Save, Key, Building, PlusCircle, Pencil, Trash2, FlaskConical } from 'lucide-react';
import {
  getSettingsAction,
  updateSettingsAction,
  getRoomsAction,
  addRoomAction,
  updateRoomAction,
  deleteRoomAction,
  getLabsAction,
  addLabAction,
  updateLabAction,
  deleteLabAction,
} from "@/app/actions/dbActions";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import AdminSidebar from "@/components/admin/AdminSidebar";
import { Room, Lab } from "@/utils/storage";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
  DialogClose,
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

export default function SettingsPage() {
  const [settings, setSettings] = useState({ teacherSecret: '' });
  const [loading, setLoading] = useState(false);
  
  const [rooms, setRooms] = useState<Room[]>([]);
  const [isRoomDialogOpen, setRoomDialogOpen] = useState(false);
  const [editingRoom, setEditingRoom] = useState<Room | null>(null);
  const [roomToDelete, setRoomToDelete] = useState<Room | null>(null);
  const [roomFormData, setRoomFormData] = useState({ name: '', capacity: '' });

  const [labs, setLabs] = useState<Lab[]>([]);
  const [isLabDialogOpen, setLabDialogOpen] = useState(false);
  const [editingLab, setEditingLab] = useState<Lab | null>(null);
  const [labToDelete, setLabToDelete] = useState<Lab | null>(null);
  const [labFormData, setLabFormData] = useState({ name: '', capacity: '' });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [currentSettings, currentRooms, currentLabs] = await Promise.all([
        getSettingsAction(),
        getRoomsAction(),
        getLabsAction(),
      ]);
      setSettings(currentSettings);
      setRooms(currentRooms);
      setLabs(currentLabs);
    } catch (e) {
      toast.error("Failed to load settings data.");
    } finally {
      setLoading(false);
    }
  };

  const handleSaveSettings = async () => {
    setLoading(true);
    try {
      await updateSettingsAction(settings);
      toast.success("Settings saved successfully.");
    } catch (error) {
      toast.error("Failed to save settings.");
    } finally {
      setLoading(false);
    }
  };

  // Room Handlers
  const handleOpenRoomDialog = (room: Room | null) => {
    setEditingRoom(room);
    setRoomFormData(room ? { name: room.name, capacity: room.capacity.toString() } : { name: '', capacity: '' });
    setRoomDialogOpen(true);
  };

  const handleSaveRoom = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!roomFormData.name || !roomFormData.capacity) {
      toast.error("Room name and capacity are required.");
      return;
    }

    setLoading(true);
    try {
      if (editingRoom) {
        await updateRoomAction(editingRoom.id, {
          name: roomFormData.name,
          capacity: parseInt(roomFormData.capacity, 10),
        });
        toast.success("Room updated successfully.");
      } else {
        await addRoomAction({
          id: `ROOM-${Date.now()}`,
          name: roomFormData.name,
          capacity: parseInt(roomFormData.capacity, 10),
        });
        toast.success("Room added successfully.");
      }
      setRoomDialogOpen(false);
      fetchData();
    } catch (error) {
      toast.error("Failed to save room.");
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteRoom = async () => {
    if (!roomToDelete) return;
    setLoading(true);
    try {
      await deleteRoomAction(roomToDelete.id);
      toast.success("Room deleted successfully.");
      setRoomToDelete(null);
      fetchData();
    } catch (error) {
      toast.error("Failed to delete room.");
    } finally {
      setLoading(false);
    }
  };

  // Lab Handlers
  const handleOpenLabDialog = (lab: Lab | null) => {
    setEditingLab(lab);
    setLabFormData(lab ? { name: lab.name, capacity: lab.capacity.toString() } : { name: '', capacity: '' });
    setLabDialogOpen(true);
  };

  const handleSaveLab = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!labFormData.name || !labFormData.capacity) {
      toast.error("Lab name and capacity are required.");
      return;
    }

    setLoading(true);
    try {
      if (editingLab) {
        await updateLabAction(editingLab.id, { name: labFormData.name });
        toast.success("Lab updated successfully.");
      } else {
        await addLabAction({
          id: `LAB-${Date.now()}`,
          name: labFormData.name,
          capacity: parseInt(labFormData.capacity, 10),
        });
        toast.success("Lab and its PCs have been added successfully.");
      }
      setLabDialogOpen(false);
      fetchData();
    } catch (error) {
      toast.error("Failed to save lab.");
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteLab = async () => {
    if (!labToDelete) return;
    setLoading(true);
    try {
      await deleteLabAction(labToDelete.id);
      toast.success("Lab deleted successfully.");
      setLabToDelete(null);
      fetchData();
    } catch (error) {
      toast.error("Failed to delete lab.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <header className="bg-primary shadow-lg sticky top-0 z-20">
        <div className="mx-auto px-8 h-16 flex items-center">
          <Image src="/logo.png" alt="AMA Student Portal" width={150} height={38} priority />
        </div>
      </header>
      <div className="flex flex-1">
        <AdminSidebar />
        <main className="flex-1 p-8 overflow-y-auto">
          <div className="max-w-4xl mx-auto">
            <div className="mb-8">
              <h1 className="text-3xl font-bold text-gray-800">System Settings</h1>
              <p className="text-muted-foreground">Configure system preferences, rooms and computer labs.</p>
            </div>
            
            <Card className="mb-8">
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Key className="h-5 w-5 text-primary" />
                  Security
                </CardTitle>
                <CardDescription>Manage security-related settings.</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="teacherSecret">Teacher Secret Code</Label>
                  <Input
                    id="teacherSecret"
                    value={settings.teacherSecret}
                    onChange={(e) => setSettings({ ...settings, teacherSecret: e.target.value })}
                    placeholder="Enter a secret code for teacher registration"
                  />
                  <p className="text-xs text-muted-foreground">Code required for teacher registration</p>
                </div>
                <div className="flex justify-end pt-4">
                  <Button onClick={handleSaveSettings} disabled={loading} className="bg-primary text-white hover:bg-primary/90">
                    {loading ? 'Saving...' : <><Save className="h-4 w-4 mr-2" /> Save Settings</>}
                  </Button>
                </div>
              </CardContent>
            </Card>

            <Card className="mb-8">
              <CardHeader className="flex flex-row items-center justify-between">
                <div>
                  <CardTitle className="flex items-center gap-2">
                    <FlaskConical className="h-5 w-5 text-primary" />
                    Manage Labs
                  </CardTitle>
                </div>
                <Button onClick={() => handleOpenLabDialog(null)} className="bg-primary hover:bg-primary/90 text-white">
                  <PlusCircle className="mr-2 h-4 w-4" /> Add Lab
                </Button>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  {labs.map(lab => (
                    <div key={lab.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border">
                      <div>
                        <p className="font-semibold">{lab.name}</p>
                        <p className="text-sm text-muted-foreground">Capacity: {lab.capacity} PCs</p>
                      </div>
                      <div className="flex gap-2">
                        <Button onClick={() => handleOpenLabDialog(lab)} variant="outline" size="sm" className="bg-blue-600 text-white hover:bg-blue-700 hover:text-white">
                          <Pencil className="mr-2 h-3 w-3" /> Edit
                        </Button>
                        <Button onClick={() => setLabToDelete(lab)} variant="destructive" size="sm">
                          <Trash2 className="mr-2 h-3 w-3" /> Delete
                        </Button>
                      </div>
                    </div>
                  ))}
                  {labs.length === 0 && <p className="text-center text-muted-foreground py-10">No labs configured.</p>}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between">
                <div>
                  <CardTitle className="flex items-center gap-2">
                    <Building className="h-5 w-5 text-primary" />
                    Manage Rooms
                  </CardTitle>
                </div>
                <Button onClick={() => handleOpenRoomDialog(null)} className="bg-primary hover:bg-primary/90 text-white">
                  <PlusCircle className="mr-2 h-4 w-4" /> Add Room
                </Button>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  {rooms.map(room => (
                    <div key={room.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border">
                      <div>
                        <p className="font-semibold">{room.name}</p>
                        <p className="text-sm text-muted-foreground">Capacity: {room.capacity} students</p>
                      </div>
                      <div className="flex gap-2">
                        <Button onClick={() => handleOpenRoomDialog(room)} variant="outline" size="sm" className="bg-blue-600 text-white hover:bg-blue-700 hover:text-white">
                          <Pencil className="mr-2 h-3 w-3" /> Edit
                        </Button>
                        <Button onClick={() => setRoomToDelete(room)} variant="destructive" size="sm">
                          <Trash2 className="mr-2 h-3 w-3" /> Delete
                        </Button>
                      </div>
                    </div>
                  ))}
                  {rooms.length === 0 && <p className="text-center text-muted-foreground py-10">No rooms configured.</p>}
                </div>
              </CardContent>
            </Card>
            
          </div>
        </main>
      </div>

      <Dialog open={isRoomDialogOpen} onOpenChange={setRoomDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingRoom ? 'Edit Room' : 'Add New Room'}</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleSaveRoom} className="space-y-4 pt-4">
            <div className="space-y-2">
              <Label htmlFor="roomName">Room Name</Label>
              <Input id="roomName" value={roomFormData.name} onChange={e => setRoomFormData({ ...roomFormData, name: e.target.value })} required />
            </div>
            <div className="space-y-2">
              <Label htmlFor="roomCapacity">Capacity</Label>
              <Input id="roomCapacity" type="number" value={roomFormData.capacity} onChange={e => setRoomFormData({ ...roomFormData, capacity: e.target.value })} required />
            </div>
            <DialogFooter>
              <DialogClose asChild><Button type="button" variant="secondary">Cancel</Button></DialogClose>
              <Button type="submit" className="bg-primary hover:bg-primary/90 text-white" disabled={loading}>{loading ? "Saving..." : "Save Room"}</Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
      
      <AlertDialog open={!!roomToDelete} onOpenChange={() => setRoomToDelete(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
            <AlertDialogDescription>
              This action cannot be undone. This will permanently delete the room <span className="font-bold">{roomToDelete?.name}</span>.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDeleteRoom} className="bg-destructive hover:bg-destructive/90">Delete</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <Dialog open={isLabDialogOpen} onOpenChange={setLabDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingLab ? 'Edit Lab' : 'Add New Lab'}</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleSaveLab} className="space-y-4 pt-4">
            <div className="space-y-2">
              <Label htmlFor="labName">Lab Name</Label>
              <Input id="labName" value={labFormData.name} onChange={e => setLabFormData({ ...labFormData, name: e.target.value })} required />
            </div>
            <div className="space-y-2">
              <Label htmlFor="labCapacity">Capacity</Label>
              <Input id="labCapacity" type="number" value={labFormData.capacity} onChange={e => setLabFormData({ ...labFormData, capacity: e.target.value })} required disabled={!!editingLab} />
              {editingLab && <p className="text-xs text-muted-foreground">Capacity cannot be changed after creation.</p>}
            </div>
            <DialogFooter>
              <DialogClose asChild><Button type="button" variant="secondary">Cancel</Button></DialogClose>
              <Button type="submit" className="bg-primary hover:bg-primary/90 text-white" disabled={loading}>{loading ? "Saving..." : "Save Lab"}</Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>

      <AlertDialog open={!!labToDelete} onOpenChange={() => setLabToDelete(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
            <AlertDialogDescription>
              This action cannot be undone. This will permanently delete the lab <span className="font-bold">{labToDelete?.name}</span> and all associated PCs.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDeleteLab} className="bg-destructive hover:bg-destructive/90">Delete</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}
